-- Run after 003a_pulse_columns.sql. Part 1 of 4.
insert into public.missions (
  mission_id_slug,
  title,
  mission,
  world,
  category,
  difficulty,
  xp,
  time_required,
  mission_path,
  tags,
  pack,
  unlock_xp,
  why_it_matters,
  completion_condition,
  reflection_prompt,
  safety_note,
  is_sensitive,
  is_active
)
values
  ('i_want_to_feel_lighter_i_only_have_5_minutes_1_do_a_one_song_mood_shift', 'Do a One-Song Mood Shift', 'Play one upbeat song and move, tidy, stretch, or dance for the full track without checking your phone.', 'Recharge', 'Fun Fuel', 'Easy', 10, 'I only have 5 minutes', 'I want to feel lighter', array['quick', 'easy', 'fun', 'joy', 'play']::text[], 'Starter', 0, 'Light movement can interrupt a heavy mood before it turns into a whole day.', 'You move for one full song without touching your phone.', 'What changed in your mood after one song?', null, false, true),
  ('i_want_to_feel_lighter_i_only_have_5_minutes_2_clear_one_tiny_annoyance', 'Clear One Tiny Annoyance', 'Fix one tiny thing that has been irritating you: refill something, throw away trash, untangle a cable, or put one item back.', 'Recharge', 'Fun Fuel', 'Easy', 10, 'I only have 5 minutes', 'I want to feel lighter', array['quick', 'easy', 'fun', 'joy', 'play']::text[], 'Starter', 0, 'Small annoyances quietly drain energy. Removing one gives you a fast sense of relief.', 'One tiny irritation is handled.', 'Which tiny annoyance was taking more space than it deserved?', null, false, true),
  ('i_want_to_feel_lighter_i_only_have_5_minutes_3_send_a_light_message', 'Send a Light Message', 'Send one low-pressure funny, warm, or playful message to someone who would enjoy it.', 'Recharge', 'Fun Fuel', 'Easy', 10, 'I only have 5 minutes', 'I want to feel lighter', array['quick', 'easy', 'fun', 'joy', 'play']::text[], 'Starter', 0, 'A light moment with another person can loosen the grip of a serious day.', 'You send one warm or playful message.', 'Who felt easy to share a lighter moment with?', null, false, true),
  ('i_want_to_feel_lighter_i_have_10_15_minutes_1_make_a_tiny_joy_list', 'Make a Tiny Joy List', 'Write down ten small things that reliably make your day feel lighter, then do or schedule one of them.', 'Recharge', 'Fun Fuel', 'Easy', 10, 'I have 10-15 minutes', 'I want to feel lighter', array['short', 'doable', 'fun', 'joy', 'play']::text[], 'Starter', 0, 'Joy becomes easier to choose when you know what actually works for you.', 'You list ten tiny joy cues and act on or schedule one.', 'Which small joy felt easiest to choose today?', null, false, true),
  ('i_want_to_feel_lighter_i_have_10_15_minutes_2_book_a_real_fun_slot', 'Book a Real Fun Slot', 'Choose one fun activity and make it real by adding a date, time, invitation, booking, or physical setup.', 'Recharge', 'Fun Fuel', 'Easy', 10, 'I have 10-15 minutes', 'I want to feel lighter', array['short', 'doable', 'fun', 'joy', 'play']::text[], 'Starter', 0, 'Fun is easier to protect when it has a real commitment or cue attached.', 'One fun activity has a date, trigger, invitation, booking, or setup.', 'What kind of fun have you been postponing?', null, false, true),
  ('i_want_to_feel_lighter_i_have_10_15_minutes_3_make_your_space_smile', 'Make Your Space Smile', 'Add one small pleasant detail to your space: open a curtain, play music, light a candle, place a photo, or move one object.', 'Recharge', 'Fun Fuel', 'Easy', 10, 'I have 10-15 minutes', 'I want to feel lighter', array['short', 'doable', 'fun', 'joy', 'play']::text[], 'Starter', 0, 'Your environment can quietly remind your body that the day is not only work.', 'One visible detail in your space feels more pleasant than before.', 'What small detail changed the room''s mood?', null, false, true),
  ('i_want_to_feel_lighter_i_have_15_30_minutes_1_take_a_treat_errand', 'Take a Treat Errand', 'Walk or go out for one small treat or pleasant practical errand, and keep your phone away except for essentials.', 'Recharge', 'Fun Fuel', 'Medium', 25, 'I have 15-30 minutes', 'I want to feel lighter', array['doable', 'focus', 'meaningful', 'fun', 'joy', 'play']::text[], 'Starter', 0, 'A tiny outing can make the day feel less trapped inside your head.', 'You complete one pleasant errand or treat run with minimal scrolling.', 'What felt different once you left your usual loop?', null, false, true),
  ('i_want_to_feel_lighter_i_have_15_30_minutes_2_refresh_a_small_corner', 'Refresh a Small Corner', 'Pick one small corner and make it more pleasant by clearing, wiping, rearranging, and adding one nice detail.', 'Recharge', 'Fun Fuel', 'Medium', 25, 'I have 15-30 minutes', 'I want to feel lighter', array['doable', 'focus', 'meaningful', 'fun', 'joy', 'play']::text[], 'Starter', 0, 'A refreshed corner gives your brain visible proof that the day can shift.', 'One corner is cleaner and more pleasant than when you started.', 'What did the corner feel like before and after?', null, false, true),
  ('i_want_to_feel_lighter_i_have_15_30_minutes_3_create_a_mini_reward_plan', 'Create a Mini Reward Plan', 'Choose one task you have been avoiding and attach a simple reward you will take immediately after doing it.', 'Recharge', 'Fun Fuel', 'Medium', 25, 'I have 15-30 minutes', 'I want to feel lighter', array['doable', 'focus', 'meaningful', 'fun', 'joy', 'play']::text[], 'Starter', 0, 'Rewards make effort feel less endless and help your brain start moving.', 'One avoided task has a clear reward attached and scheduled.', 'What reward would actually make effort feel lighter?', null, false, true),
  ('i_want_to_feel_lighter_i_have_more_than_30_minutes_1_do_a_joy_walk', 'Do a Joy Walk', 'Take a 30-minute walk with the goal of noticing, photographing, or collecting five things that feel pleasant.', 'Recharge', 'Fun Fuel', 'Hard', 50, 'I have more than 30 minutes', 'I want to feel lighter', array['deep', 'purpose', 'fun', 'joy', 'play']::text[], 'Starter', 0, 'Looking for small good things trains attention away from the same old weight.', 'You complete a walk and capture five pleasant details.', 'Which detail surprised you most?', null, false, true),
  ('i_want_to_feel_lighter_i_have_more_than_30_minutes_2_give_a_hobby_one_full_block', 'Give a Hobby One Full Block', 'Spend 45 minutes on a hobby with no productivity goal: play, cook, read, make, garden, sing, or learn for enjoyment.', 'Recharge', 'Fun Fuel', 'Hard', 50, 'I have more than 30 minutes', 'I want to feel lighter', array['deep', 'purpose', 'fun', 'joy', 'play']::text[], 'Starter', 0, 'Pleasure gets squeezed out when every activity has to prove its usefulness.', 'You spend one uninterrupted block on a hobby for its own sake.', 'What felt good once usefulness was not the point?', null, false, true),
  ('i_want_to_feel_lighter_i_have_more_than_30_minutes_3_plan_a_low_pressure_hangout', 'Plan a Low-Pressure Hangout', 'Set up one low-pressure hangout, call, game, walk, or meal with someone you enjoy being around.', 'Recharge', 'Fun Fuel', 'Hard', 50, 'I have more than 30 minutes', 'I want to feel lighter', array['deep', 'purpose', 'fun', 'joy', 'play']::text[], 'Starter', 0, 'Shared ease can be one of the fastest ways to feel lighter.', 'One low-pressure plan is proposed, scheduled, or confirmed.', 'Who makes life feel a little less heavy?', null, false, true),
  ('i_want_to_slow_down_i_only_have_5_minutes_1_make_a_quiet_drink_pause', 'Make a Quiet Drink Pause', 'Make water, tea, coffee, or another drink and take the first five sips without a screen.', 'Recharge', 'Refuel', 'Easy', 10, 'I only have 5 minutes', 'I want to slow down', array['quick', 'easy', 'calm', 'mindful', 'rest']::text[], 'Starter', 0, 'A small pause teaches your nervous system that not every minute needs input.', 'You take five slow sips without looking at a screen.', 'What did you notice when nothing else was happening?', null, false, true),
  ('i_want_to_slow_down_i_only_have_5_minutes_2_write_the_load_down', 'Write the Load Down', 'Write every open worry, task, or loop in your head for five minutes without solving anything.', 'Recharge', 'Refuel', 'Easy', 10, 'I only have 5 minutes', 'I want to slow down', array['quick', 'easy', 'calm', 'mindful', 'rest']::text[], 'Starter', 0, 'The mind slows down when it stops having to hold everything at once.', 'You capture the mental load on paper or in a note.', 'Which thought kept repeating most loudly?', null, false, true),
  ('i_want_to_slow_down_i_only_have_5_minutes_3_do_the_slow_exhale_reset', 'Do the Slow Exhale Reset', 'Take ten slow breaths with longer exhales, then name one thing that can wait.', 'Recharge', 'Refuel', 'Easy', 10, 'I only have 5 minutes', 'I want to slow down', array['quick', 'easy', 'calm', 'mindful', 'rest']::text[], 'Starter', 0, 'Slowing the body first can soften urgency in the mind.', 'You take ten slow breaths and name one thing that can wait.', 'What felt less urgent after breathing?', null, false, true),
  ('i_want_to_slow_down_i_have_10_15_minutes_1_build_tonight_s_phone_landing_zone', 'Build Tonight''s Phone Landing Zone', 'Choose a charging spot away from bed, place one offline wind-down item beside your bed, and set your phone there tonight.', 'Recharge', 'Refuel', 'Easy', 10, 'I have 10-15 minutes', 'I want to slow down', array['short', 'doable', 'calm', 'mindful', 'rest']::text[], 'Starter', 0, 'A prepared environment makes it easier to rest without negotiating later.', 'Your phone landing zone is chosen and one offline item is ready.', 'What usually pulls you back to your phone at night?', null, false, true),
  ('i_want_to_slow_down_i_have_10_15_minutes_2_do_a_gentle_stretch_scan', 'Do a Gentle Stretch Scan', 'Spend ten minutes stretching slowly from neck to feet, pausing wherever your body feels tight.', 'Recharge', 'Refuel', 'Easy', 10, 'I have 10-15 minutes', 'I want to slow down', array['short', 'doable', 'calm', 'mindful', 'rest']::text[], 'Starter', 0, 'Slow movement can bring your attention back into your body without demanding intensity.', 'You complete a slow ten-minute stretch or mobility scan.', 'Where did your body ask for more patience?', null, false, true),
  ('i_want_to_slow_down_i_have_10_15_minutes_3_choose_one_thing_to_postpone', 'Choose One Thing to Postpone', 'Look at your list and deliberately move one non-urgent task to another day or remove it completely.', 'Recharge', 'Refuel', 'Easy', 10, 'I have 10-15 minutes', 'I want to slow down', array['short', 'doable', 'calm', 'mindful', 'rest']::text[], 'Starter', 0, 'Slowing down sometimes means deciding what does not need today''s energy.', 'One non-urgent task is postponed, removed, or delegated.', 'What became lighter when you let one thing wait?', null, false, true),
  ('i_want_to_slow_down_i_have_15_30_minutes_1_take_a_no_input_walk', 'Take a No-Input Walk', 'Walk for 20 minutes without music, podcasts, calls, or scrolling.', 'Recharge', 'Refuel', 'Medium', 25, 'I have 15-30 minutes', 'I want to slow down', array['doable', 'focus', 'meaningful', 'calm', 'mindful', 'rest']::text[], 'Starter', 0, 'Silence gives your thoughts room to settle instead of being constantly replaced.', 'You complete a no-input walk.', 'What surfaced once there was no input?', null, false, true),
  ('i_want_to_slow_down_i_have_15_30_minutes_2_make_a_slow_meal_setup', 'Make a Slow Meal Setup', 'Prepare one simple snack or meal component slowly: wash fruit, cut vegetables, cook eggs, or set up breakfast.', 'Recharge', 'Refuel', 'Medium', 25, 'I have 15-30 minutes', 'I want to slow down', array['doable', 'focus', 'meaningful', 'calm', 'mindful', 'rest']::text[], 'Starter', 0, 'Basic care feels different when it is not rushed like another task.', 'One simple food or drink setup is ready.', 'What changed when you moved at a slower pace?', null, false, true),
  ('i_want_to_slow_down_i_have_15_30_minutes_3_close_three_open_loops', 'Close Three Open Loops', 'Pick three small open loops and close them: reply, file, delete, put away, pay, schedule, or decide.', 'Recharge', 'Refuel', 'Medium', 25, 'I have 15-30 minutes', 'I want to slow down', array['doable', 'focus', 'meaningful', 'calm', 'mindful', 'rest']::text[], 'Starter', 0, 'Open loops create background noise. Closing a few helps your mind settle.', 'Three small open loops are closed or clearly decided.', 'Which loop had been stealing the most attention?', null, false, true),
  ('i_want_to_slow_down_i_have_more_than_30_minutes_1_create_a_screen_free_evening_block', 'Create a Screen-Free Evening Block', 'Choose a 60-minute screen-free block tonight and prepare what you will do instead: book, walk, bath, call, cooking, or music.', 'Recharge', 'Refuel', 'Hard', 50, 'I have more than 30 minutes', 'I want to slow down', array['deep', 'purpose', 'calm', 'mindful', 'rest']::text[], 'Starter', 0, 'Rest needs a plan when screens are the default.', 'A 60-minute screen-free block is scheduled and prepared.', 'What would make tonight feel more restful?', null, false, true),
  ('i_want_to_slow_down_i_have_more_than_30_minutes_2_do_a_gentle_room_reset', 'Do a Gentle Room Reset', 'Reset one room slowly: clear surfaces, put things back, wipe one area, and make the room easier to enter.', 'Recharge', 'Refuel', 'Hard', 50, 'I have more than 30 minutes', 'I want to slow down', array['deep', 'purpose', 'calm', 'mindful', 'rest']::text[], 'Starter', 0, 'A calmer room gives your body a quieter place to land.', 'One room feels visibly calmer and easier to use.', 'What changed in your body when the room changed?', null, false, true),
  ('i_want_to_slow_down_i_have_more_than_30_minutes_3_take_a_slow_admin_hour', 'Take a Slow Admin Hour', 'Spend 45 minutes handling life admin at a calm pace: bills, forms, appointments, files, or messages, with one break in the middle.', 'Recharge', 'Refuel', 'Hard', 50, 'I have more than 30 minutes', 'I want to slow down', array['deep', 'purpose', 'calm', 'mindful', 'rest']::text[], 'Starter', 0, 'Admin feels less threatening when it is contained and paced.', 'One calm admin block is completed with visible progress.', 'What felt more manageable after giving it time?', null, false, true)

on conflict (mission_id_slug) do update set
  title = excluded.title,
  mission = excluded.mission,
  world = excluded.world,
  category = excluded.category,
  difficulty = excluded.difficulty,
  xp = excluded.xp,
  time_required = excluded.time_required,
  mission_path = excluded.mission_path,
  tags = excluded.tags,
  pack = excluded.pack,
  unlock_xp = excluded.unlock_xp,
  why_it_matters = excluded.why_it_matters,
  completion_condition = excluded.completion_condition,
  reflection_prompt = excluded.reflection_prompt,
  safety_note = excluded.safety_note,
  is_sensitive = excluded.is_sensitive,
  is_active = excluded.is_active;
